/* ══════════════════════════════════════════
   PORTFOLIO — ZENAIDA JORDÁ
   style.css
══════════════════════════════════════════ */

/* ── Variables ── */
:root {
  --pink:    #ff0091;
  --pink-dk: #d6007a;
  --pink-lt: #ff33a8;
  --black:   #000000;
  --black-2: #1a1a1a;
  --white:   #ffffff;
  --gray:    #f5f5f5;
  --text:    #1a1a1a;
  --muted:   #666666;
  --border:  #e0e0e0;

  --font-heading: 'Horizon', 'Poppins', sans-serif;
  --font-body:    'Poppins', system-ui, sans-serif;

  --radius: 12px;
  --shadow: 0 4px 24px rgba(0, 0, 0, 0.1);
  --shadow-md: 0 8px 40px rgba(0, 0, 0, 0.15);

  --max-w: 1120px;
  --section-py: 96px;
}

/* ── Reset ── */
*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
html { scroll-behavior: smooth; font-size: 16px; }

/* Animaciones personalizadas */
@keyframes typewriter {
  from { width: 0; }
  to { width: 100%; }
}

@keyframes blinkCursor {
  from, to { border-right-color: transparent }
  50% { border-right-color: var(--pink); }
}

.typewriter-text {
  overflow: hidden; /* Oculta el texto hasta que aparezca */
  white-space: normal;
  display: inline-block;
  opacity: 0;
  animation: fadeInText 1s ease 1s forwards;
}

@keyframes fadeInText {
  from { opacity: 0; transform: translateY(10px); }
  to { opacity: 1; transform: translateY(0); }
}

/* Efectos de Scroll Reveal */
.reveal-on-scroll {
  opacity: 0;
  transform: translateY(40px);
  transition: opacity 0.8s cubic-bezier(0.5, 0, 0, 1), transform 0.8s cubic-bezier(0.5, 0, 0, 1);
  will-change: opacity, transform;
}

.reveal-on-scroll.is-revealed {
  opacity: 1;
  transform: translateY(0);
}

body {
  font-family: var(--font-body);
  color: var(--text);
  background: var(--white);
  line-height: 1.7;
  -webkit-font-smoothing: antialiased;
}
img { display: block; max-width: 100%; }
a { color: inherit; text-decoration: none; }
ul { list-style: none; }
button { cursor: pointer; border: none; background: none; }

/* ── Utilidades ── */
.container {
  width: 100%;
  max-width: var(--max-w);
  margin-inline: auto;
  padding-inline: 24px;
}
.section { padding-block: var(--section-py); }
.bg-light { background: var(--gray); }

.section-header {
  text-align: center;
  margin-bottom: 56px;
}
.section-header h2 {
  font-family: var(--font-heading);
  font-size: clamp(2rem, 4vw, 2.75rem);
  color: var(--black);
  margin-top: 8px;
}
.section-subtitle {
  max-width: 640px;
  margin: 16px auto 0;
  color: var(--muted);
  font-size: 1.05rem;
}
.section-header--light h2 { color: var(--white); }
.section-header--light .section-subtitle { color: rgba(255,255,255,.75); }

.tag {
  display: inline-block;
  background: var(--pink);
  color: var(--white);
  font-size: .75rem;
  font-weight: 600;
  letter-spacing: .12em;
  text-transform: uppercase;
  padding: 4px 12px;
  border-radius: 100px;
}
.tag--light {
  background: rgba(255,255,255,.2);
  color: var(--white);
}

/* ── Botones ── */
.btn {
  display: inline-flex;
  align-items: center;
  gap: 8px;
  padding: 14px 28px;
  border-radius: 8px;
  font-family: var(--font-body);
  font-size: .95rem;
  font-weight: 600;
  transition: all .2s ease;
  white-space: nowrap;
}
.btn-primary {
  background: var(--pink);
  color: var(--white);
  box-shadow: 0 2px 12px rgba(255, 0, 145, .35);
}
.btn-primary:hover {
  background: var(--pink-lt);
  transform: translateY(-2px);
  box-shadow: 0 4px 20px rgba(255, 0, 145, .45);
}
.btn-outline {
  border: 2px solid var(--white);
  color: var(--white);
}
.btn-outline:hover {
  background: var(--white);
  color: var(--black);
}
.btn-full { width: 100%; justify-content: center; }

/* Efecto Ripple para los botones hover */
.btn-hover-effect {
  position: relative;
  overflow: hidden;
}
.btn-hover-effect::after {
  content: "";
  display: block;
  position: absolute;
  top: 50%;
  left: 50%;
  width: 300px;
  height: 300px;
  background: rgba(255, 255, 255, 0.15);
  border-radius: 50%;
  transform: translate(-50%, -50%) scale(0);
  opacity: 0;
  transition: transform 0.6s ease-out, opacity 0.6s ease-out;
  pointer-events: none;
}
.btn-hover-effect:hover::after {
  transform: translate(-50%, -50%) scale(1);
  opacity: 1;
}

/* ══════════════════════════════════════════
   NAVEGACIÓN
══════════════════════════════════════════ */
#navbar {
  position: fixed;
  top: 0; left: 0; right: 0;
  z-index: 100;
  background: transparent;
  transition: background .3s, box-shadow .3s;
}
#navbar.scrolled {
  background: var(--black);
  box-shadow: 0 2px 20px rgba(0,0,0,.25);
}
.nav-inner {
  max-width: var(--max-w);
  margin-inline: auto;
  padding: 18px 24px;
  display: flex;
  align-items: center;
  justify-content: space-between;
}
.nav-logo {
  font-family: var(--font-heading);
  font-size: 1.5rem;
  font-weight: 700;
  color: var(--white);
  letter-spacing: .05em;
}
.nav-links {
  display: flex;
  align-items: center;
  gap: 32px;
}
.nav-links a {
  color: rgba(255,255,255,.85);
  font-size: .9rem;
  font-weight: 500;
  transition: color .2s;
}
.nav-links a:hover { color: var(--pink-lt); }
.nav-cta {
  background: var(--pink) !important;
  color: var(--white) !important;
  padding: 8px 20px;
  border-radius: 6px;
  font-weight: 600 !important;
}
.nav-cta:hover { background: var(--pink-lt) !important; }
.nav-toggle {
  display: none;
  flex-direction: column;
  gap: 5px;
  padding: 4px;
}
.nav-toggle span {
  display: block;
  width: 24px; height: 2px;
  background: var(--white);
  border-radius: 2px;
  transition: all .3s;
}

/* ══════════════════════════════════════════
   HERO
══════════════════════════════════════════ */
.hero {
  min-height: 100vh;
  background: linear-gradient(135deg, var(--black) 0%, var(--black-2) 100%);
  color: var(--white);
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  position: relative;
  overflow: hidden;
}
.hero::before {
  content: '';
  position: absolute;
  top: -40%; right: -20%;
  width: 600px; height: 600px;
  border-radius: 50%;
  background: radial-gradient(circle, rgba(255,0,145,.18) 0%, transparent 70%);
  pointer-events: none;
}
.hero-content {
  width: 100%;
  max-width: var(--max-w);
  padding-inline: 24px;
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 64px;
  align-items: center;
}
.hero-eyebrow {
  font-size: .85rem;
  font-weight: 600;
  letter-spacing: .18em;
  text-transform: uppercase;
  color: var(--pink-lt);
  margin-bottom: 16px;
}
.hero-title {
  font-family: var(--font-heading);
  font-size: clamp(3rem, 6vw, 5rem);
  line-height: 1.1;
  margin-bottom: 24px;
}
.hero-title .accent { color: var(--pink-lt); }
.hero-subtitle {
  font-size: 1.1rem;
  color: rgba(255,255,255,.8);
  max-width: 480px;
  margin-bottom: 40px;
}
.hero-actions { display: flex; gap: 16px; flex-wrap: wrap; }
.hero-image {
  display: flex;
  justify-content: center;
}

/* Efecto imagen flotante hero */
.floating-img {
  animation: float 6s ease-in-out infinite;
}

@keyframes float {
  0% { transform: translateY(0px) rotate(0deg); }
  50% { transform: translateY(-15px) rotate(2deg); }
  100% { transform: translateY(0px) rotate(0deg); }
}

.hero-image img {
  width: 380px;
  height: 380px;
  object-fit: cover;
  border-radius: 50%;
  border: 5px solid rgba(255, 0, 145, .5);
  box-shadow: 0 20px 60px rgba(0,0,0,.4);
}
.scroll-hint {
  position: absolute;
  bottom: 32px;
  left: 50%;
  transform: translateX(-50%);
  color: rgba(255,255,255,.5);
  font-size: 1.2rem;
  animation: bounce 2s infinite;
}
@keyframes bounce {
  0%, 100% { transform: translateX(-50%) translateY(0); }
  50% { transform: translateX(-50%) translateY(8px); }
}

/* ══════════════════════════════════════════
   SOBRE MÍ
══════════════════════════════════════════ */
